"use client";

import * as React from "react";
import {
  IconCalendarEvent,
  IconUsers,
  IconChairDirector,
  IconAlertTriangle,
  IconUserPlus,
  IconPhone,
  IconChevronRight,
} from "@tabler/icons-react";
import {
  Container,
  StatGroup,
  Meter,
  ScheduleGrid,
  DataTable,
  PersonCell,
  Badge,
  Button,
  Select,
  NumberInput,
  Separator,
  MetadataList,
  Alert,
  AlertTitle,
  AlertDescription,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  type ScheduleCell,
  type ScheduleCellTone,
  type ColumnDef,
} from "@gunjo/ui";
import {
  RESERVATIONS,
  TABLES,
  TIME_SLOTS,
  SERVICE_DATE,
  STAFF_OPTIONS,
  type Reservation,
  type ReservationStatus,
} from "./data";
import {
  STATUS_META,
  REQUEST_BADGE,
  STATUS_ORDER,
  summarize,
  buildSlotMap,
  findDoubleBookings,
  freeTablesAt,
  yen,
} from "./helpers";

export default function RestaurantReservationsPage() {
  // 予約は state（来店状況の更新・ウォークイン追加で変化する）
  const [reservations, setReservations] = React.useState<Reservation[]>(RESERVATIONS);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);
  const [walkinOpen, setWalkinOpen] = React.useState(false);

  const selected = reservations.find((r) => r.id === selectedId) ?? null;

  // 派生データ
  const summary = React.useMemo(() => summarize(reservations), [reservations]);
  const slotMap = React.useMemo(() => buildSlotMap(reservations), [reservations]);
  const conflicts = React.useMemo(() => findDoubleBookings(slotMap), [slotMap]);
  const byId = React.useMemo(
    () => new Map(reservations.map((r) => [r.id, r])),
    [reservations]
  );

  // 来店状況の更新
  const updateStatus = React.useCallback(
    (id: string, status: ReservationStatus) => {
      setReservations((prev) =>
        prev.map((r) => (r.id === id ? { ...r, status } : r))
      );
    },
    []
  );

  // ── サマリーメトリクス ────────────────────────────
  const stats = [
    {
      label: "本日の予約組数",
      value: `${summary.parties}組`,
      hint: `総来店人数 ${summary.guests}名`,
    },
    {
      label: "来店済",
      value: `${summary.arrived}組`,
      hint: `着席中 ${summary.seatedTables}卓`,
    },
    {
      label: "満席率",
      value: `${summary.occupancyPct}%`,
      hint: `予約埋まり ${summary.reservedTables}/${TABLES.length}卓`,
    },
    {
      label: "ノーショー",
      value: `${summary.noshow}件`,
      tone: summary.noshow > 0 ? ("negative" as const) : ("neutral" as const),
      hint: "当日連絡なし",
    },
    {
      label: "回転率",
      value: `${summary.turnover}回転`,
      hint: `全${TABLES.length}卓ベース`,
    },
    {
      label: "予測売上",
      value: yen(summary.forecastSales),
      hint: "有効予約 × 客単価",
    },
  ];

  // ── 卓×時間グリッド ──────────────────────────────
  const gridRows = TABLES.map((t) => ({
    id: t.id,
    label: t.id,
    sublabel: `${t.zone}・${t.seats}名`,
    ariaLabel: `卓${t.id}（${t.zone}、${t.seats}名）`,
  }));
  const gridColumns = TIME_SLOTS.map((s) => ({ id: s, label: s }));

  const gridCells: ScheduleCell[] = [];
  for (const t of TABLES) {
    for (const slot of TIME_SLOTS) {
      const ids = slotMap.get(`${t.id}::${slot}`);
      if (!ids || ids.length === 0) continue;
      const isStart = ids.some((id) => byId.get(id)?.time === slot);
      const isConflict = ids.some((id) => conflicts.has(id));
      const primaryId = ids[0];
      const r = byId.get(primaryId);
      if (!r) continue;

      let tone: ScheduleCellTone = "primary";
      if (isConflict) tone = "destructive";
      else if (r.status === "seated") tone = "info";
      else if (r.status === "paid") tone = "success";

      // 継続スロットは控えめ表示（開始スロットだけ氏名）
      const names = ids.map((id) => byId.get(id)?.name).filter(Boolean);
      gridCells.push({
        rowId: t.id,
        colId: slot,
        tone,
        description: isConflict
          ? `重複: ${names.join("・")}`
          : `${r.name}・${r.party}名`,
        onSelect: () => setSelectedId(primaryId),
        content: (
          <div className="flex min-w-0 flex-col gap-0.5 text-left">
            {isStart || isConflict ? (
              <span className="truncate text-xs font-semibold leading-tight">
                {isConflict && (
                  <IconAlertTriangle
                    className="mr-0.5 inline h-3 w-3 align-[-2px]"
                    aria-hidden
                  />
                )}
                {ids.length > 1 ? `重複 ${ids.length}件` : r.name}
              </span>
            ) : (
              <span aria-hidden className="text-xs text-muted-foreground">
                ↑
              </span>
            )}
            {(isStart || isConflict) && (
              <span className="truncate text-[10px] leading-tight text-muted-foreground">
                {r.party}名・{STATUS_META[r.status].label}
              </span>
            )}
          </div>
        ),
      });
    }
  }

  // ── 予約一覧テーブル列定義 ───────────────────────
  const columns: ColumnDef<Reservation>[] = [
    {
      id: "time",
      accessorKey: "time",
      header: "時間",
      cell: ({ row }) => (
        <div className="whitespace-nowrap tabular-nums font-medium">
          {row.original.time}
        </div>
      ),
    },
    {
      id: "name",
      accessorKey: "name",
      header: "予約者",
      cell: ({ row }) => {
        const r = row.original;
        return (
          <PersonCell
            name={r.name}
            secondary={`${r.party}名・卓${r.tableId}`}
            tertiary={r.course}
            size="sm"
            trailing={
              conflicts.has(r.id) ? (
                <Badge variant="destructive" icon={<IconAlertTriangle />}>
                  重複
                </Badge>
              ) : undefined
            }
          />
        );
      },
    },
    {
      id: "status",
      accessorKey: "status",
      header: "来店状況",
      cell: ({ row }) => {
        const meta = STATUS_META[row.original.status];
        return <Badge variant={meta.badge}>{meta.label}</Badge>;
      },
    },
    {
      id: "requests",
      header: "要望",
      enableSorting: false,
      cell: ({ row }) => {
        const reqs = row.original.requests;
        if (reqs.length === 0)
          return <span className="text-xs text-muted-foreground">—</span>;
        return (
          <div className="flex flex-wrap gap-1">
            {reqs.map((req, i) => (
              <Badge key={i} variant={REQUEST_BADGE[req.kind]}>
                {req.label}
              </Badge>
            ))}
          </div>
        );
      },
    },
    {
      id: "staff",
      accessorKey: "staff",
      header: "担当",
      cell: ({ row }) => (
        <span className="text-sm text-muted-foreground">{row.original.staff}</span>
      ),
    },
    {
      id: "drill",
      header: "",
      enableSorting: false,
      cell: () => (
        <IconChevronRight
          className="h-4 w-4 text-muted-foreground"
          aria-hidden
        />
      ),
    },
  ];

  // モバイル: 行をカード表示
  const renderResvCard = (r: Reservation) => {
    const meta = STATUS_META[r.status];
    return (
      <div className="flex flex-col gap-2">
        <div className="flex items-start justify-between gap-2">
          <PersonCell
            name={r.name}
            secondary={`${r.time}・${r.party}名・卓${r.tableId}`}
            tertiary={r.course}
            size="sm"
          />
          <Badge variant={meta.badge}>{meta.label}</Badge>
        </div>
        {(r.requests.length > 0 || conflicts.has(r.id)) && (
          <div className="flex flex-wrap gap-1 pl-11">
            {conflicts.has(r.id) && (
              <Badge variant="destructive" icon={<IconAlertTriangle />}>
                重複
              </Badge>
            )}
            {r.requests.map((req, i) => (
              <Badge key={i} variant={REQUEST_BADGE[req.kind]}>
                {req.label}
              </Badge>
            ))}
          </div>
        )}
      </div>
    );
  };

  return (
    <Container size="2xl" className="px-4 py-6 sm:px-6 sm:py-8">
      {/* ヘッダー */}
      <header className="mb-6 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <p className="text-xs font-medium text-muted-foreground">
            ビストロ 蒼海 — ホール管理
          </p>
          <h1 className="text-2xl font-bold tracking-tight">予約・来店管理</h1>
          <p className="mt-0.5 text-sm text-muted-foreground">{SERVICE_DATE}</p>
        </div>
        <Button
          variant="primary"
          onClick={() => setWalkinOpen(true)}
          aria-haspopup="dialog"
        >
          <IconUserPlus className="h-4 w-4" aria-hidden />
          ウォークイン受付
        </Button>
      </header>

      {/* ダブルブッキング警告 */}
      {conflicts.size > 0 && (
        <Alert variant="destructive" className="mb-6">
          <IconAlertTriangle className="h-4 w-4" aria-hidden />
          <AlertTitle>ダブルブッキングを検知（{conflicts.size}件）</AlertTitle>
          <AlertDescription>
            同じ卓・同じ時間帯に複数の予約が入っています。卓×時間グリッドの赤いマスを確認し、卓の振り直しをしてください。
          </AlertDescription>
        </Alert>
      )}

      {/* サマリーメトリクス + 満席率メーター */}
      <section aria-label="本日のサマリー" className="mb-6 space-y-4">
        <StatGroup items={stats} cols={{ base: 2, md: 3, lg: 6 }} />
        <div className="rounded-lg border border-border bg-card p-4">
          <div className="mb-2 flex items-center justify-between">
            <span className="text-sm font-medium">現在の満席率（着席卓ベース）</span>
            <span className="text-sm text-muted-foreground tabular-nums">
              {summary.seatedTables} / {TABLES.length} 卓
            </span>
          </div>
          {/* NOTE: `direction="higher-is-better"` with target=max paints the bar
              solid red at low occupancy — a false alarm early in service. We want
              a neutral "fill toward capacity" read, so we force `tone="info"` and
              keep `target` purely as the full-house marker line. */}
          <Meter
            value={summary.seatedTables}
            max={TABLES.length}
            tone="info"
            target={TABLES.length}
            label="満席率"
            unit="卓"
          />
        </div>
      </section>

      {/* タブ: 予約一覧 / 卓×時間グリッド */}
      <Tabs defaultValue="list" className="w-full">
        <TabsList>
          <TabsTrigger value="list">
            <IconCalendarEvent className="mr-1.5 h-4 w-4" aria-hidden />
            予約一覧
          </TabsTrigger>
          <TabsTrigger value="grid">
            <IconChairDirector className="mr-1.5 h-4 w-4" aria-hidden />
            卓 × 時間
          </TabsTrigger>
        </TabsList>

        {/* 予約一覧 */}
        <TabsContent value="list" className="mt-4">
          <DataTable
            columns={columns}
            data={reservations}
            filter={{ columnId: "name", placeholder: "予約者名で絞り込み…" }}
            pageSize={25}
            onRowClick={(r) => setSelectedId(r.id)}
            renderCard={renderResvCard}
          />
        </TabsContent>

        {/* 卓×時間グリッド */}
        <TabsContent value="grid" className="mt-4">
          <div className="mb-3 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
            <LegendDot toneClass="bg-primary/20 border-primary/40" label="予約済" />
            <LegendDot toneClass="bg-info-subtle border-info-border" label="来店中" />
            <LegendDot toneClass="bg-success-subtle border-success-border" label="会計済" />
            <LegendDot
              toneClass="bg-destructive-subtle border-destructive ring-1 ring-destructive"
              label="重複（要対応）"
            />
            <span className="ml-auto">マスをクリックで予約詳細</span>
          </div>
          <ScheduleGrid
            label="卓×時間 予約状況グリッド"
            cornerLabel="卓 \ 時刻"
            rows={gridRows}
            columns={gridColumns}
            cells={gridCells}
            minColumnWidth={88}
            rowHeaderWidth={84}
          />
        </TabsContent>
      </Tabs>

      {/* 予約詳細パネル（ドリルイン） */}
      <Sheet
        open={selected !== null}
        onOpenChange={(open) => !open && setSelectedId(null)}
      >
        <SheetContent
          side="right"
          className="w-full overflow-y-auto sm:max-w-md"
          closeLabel="閉じる"
        >
          {selected && (
            <ReservationDetail
              reservation={selected}
              isConflict={conflicts.has(selected.id)}
              onUpdateStatus={(s) => updateStatus(selected.id, s)}
            />
          )}
        </SheetContent>
      </Sheet>

      {/* ウォークイン受付ダイアログ */}
      <WalkinDialog
        open={walkinOpen}
        onOpenChange={setWalkinOpen}
        slotMap={slotMap}
        onSeat={(r) => {
          setReservations((prev) => [...prev, r]);
          setWalkinOpen(false);
          setSelectedId(r.id);
        }}
      />
    </Container>
  );
}

// ── グリッド凡例ドット ──────────────────────────────
function LegendDot({ toneClass, label }: { toneClass: string; label: string }) {
  return (
    <span className="inline-flex items-center gap-1.5">
      <span
        aria-hidden
        className={`inline-block h-3 w-3 rounded-sm border ${toneClass}`}
      />
      {label}
    </span>
  );
}

// ── 予約詳細パネル ──────────────────────────────────
function ReservationDetail({
  reservation: r,
  isConflict,
  onUpdateStatus,
}: {
  reservation: Reservation;
  isConflict: boolean;
  onUpdateStatus: (s: ReservationStatus) => void;
}) {
  const meta = STATUS_META[r.status];
  return (
    <div className="flex flex-col gap-5">
      <SheetHeader className="pr-8 text-left">
        <SheetTitle className="flex items-center gap-2">
          {r.name}
          <Badge variant={meta.badge}>{meta.label}</Badge>
        </SheetTitle>
        <SheetDescription>
          {r.kana} ・ {r.time}〜 ・ 卓{r.tableId} ・ {r.party}名
        </SheetDescription>
      </SheetHeader>

      {isConflict && (
        <Alert variant="destructive">
          <IconAlertTriangle className="h-4 w-4" aria-hidden />
          <AlertTitle>卓が重複しています</AlertTitle>
          <AlertDescription>
            同じ時間帯に卓{r.tableId}へ別の予約があります。卓の振り直しが必要です。
          </AlertDescription>
        </Alert>
      )}

      {/* 顧客情報 */}
      <section>
        <h3 className="mb-2 text-sm font-semibold">顧客情報</h3>
        <MetadataList
          variant="compact"
          items={[
            { label: "来店回数", value: `${r.visits}回` },
            { label: "前回来店", value: r.lastVisit ?? "—（新規）" },
            {
              label: "電話",
              value: (
                <span className="inline-flex items-center gap-1 tabular-nums">
                  <IconPhone className="h-3.5 w-3.5" aria-hidden />
                  {r.phone}
                </span>
              ),
            },
            { label: "客単価（予測）", value: yen(r.spendPerHead) },
          ]}
        />
      </section>

      <Separator />

      {/* 予約内容 */}
      <section>
        <h3 className="mb-2 text-sm font-semibold">予約内容</h3>
        <MetadataList
          variant="compact"
          items={[
            { label: "コース", value: r.course },
            { label: "人数", value: `${r.party}名` },
            { label: "担当スタッフ", value: r.staff },
          ]}
        />
      </section>

      {/* 要望 */}
      <section>
        <h3 className="mb-2 text-sm font-semibold">ご要望・特記</h3>
        {r.requests.length > 0 ? (
          <div className="mb-2 flex flex-wrap gap-1">
            {r.requests.map((req, i) => (
              <Badge key={i} variant={REQUEST_BADGE[req.kind]}>
                {req.label}
              </Badge>
            ))}
          </div>
        ) : (
          <p className="text-sm text-muted-foreground">特になし</p>
        )}
        {r.memo && (
          <p className="rounded-md bg-muted/50 p-2.5 text-sm leading-relaxed">
            {r.memo}
          </p>
        )}
      </section>

      <Separator />

      {/* 来店状況の更新 */}
      <section>
        <h3 className="mb-2 text-sm font-semibold">来店状況の更新</h3>
        <div className="flex flex-wrap gap-2">
          {STATUS_ORDER.map((s) => {
            const sMeta = STATUS_META[s];
            const active = r.status === s;
            return (
              <Button
                key={s}
                size="sm"
                variant={active ? "primary" : "outline"}
                aria-pressed={active}
                onClick={() => onUpdateStatus(s)}
              >
                {sMeta.label}
              </Button>
            );
          })}
          <Separator orientation="vertical" className="mx-1 h-8" />
          <Button
            size="sm"
            variant="outline"
            aria-pressed={r.status === "noshow"}
            onClick={() => onUpdateStatus("noshow")}
          >
            ノーショー
          </Button>
          <Button
            size="sm"
            variant="ghost"
            aria-pressed={r.status === "cancelled"}
            onClick={() => onUpdateStatus("cancelled")}
          >
            キャンセル
          </Button>
        </div>
      </section>
    </div>
  );
}

// ── ウォークイン受付ダイアログ ──────────────────────
function WalkinDialog({
  open,
  onOpenChange,
  slotMap,
  onSeat,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  slotMap: ReturnType<typeof buildSlotMap>;
  onSeat: (r: Reservation) => void;
}) {
  const [name, setName] = React.useState("");
  const [party, setParty] = React.useState(2);
  const [slot, setSlot] = React.useState(TIME_SLOTS[2]); // 18:00
  const [tableId, setTableId] = React.useState("");
  const [staff, setStaff] = React.useState(STAFF_OPTIONS[0]);

  // 選択スロットで空いている卓
  const free = React.useMemo(() => freeTablesAt(slot, slotMap), [slot, slotMap]);
  // 人数が席数に収まる卓だけを推奨
  const fitting = free.filter(
    (id) => (TABLES.find((t) => t.id === id)?.seats ?? 0) >= party
  );

  // スロット変更で、選択中の卓が埋まったらリセット
  React.useEffect(() => {
    if (tableId && !free.includes(tableId)) setTableId("");
  }, [free, tableId]);

  // ダイアログを開くたびに初期化
  React.useEffect(() => {
    if (open) {
      setName("");
      setParty(2);
      setTableId("");
    }
  }, [open]);

  const canSeat = name.trim() !== "" && tableId !== "";

  const handleSeat = () => {
    if (!canSeat) return;
    const seats = TABLES.find((t) => t.id === tableId)?.seats ?? party;
    onSeat({
      id: `w_${Date.now()}`,
      name: name.trim(),
      kana: "ウォークイン",
      party,
      time: slot,
      durationSlots: 3,
      tableId,
      course: "アラカルト",
      status: "seated",
      requests: [{ label: "ウォークイン", kind: "other" }],
      staff,
      visits: 0,
      spendPerHead: 6500,
      memo: `ウォークイン受付（席数${seats}の卓${tableId}へ案内）。`,
      phone: "—",
    });
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>ウォークイン受付</DialogTitle>
          <DialogDescription>
            空いている卓に当日客を案内します。時間帯を選ぶと空卓が絞り込まれます。
          </DialogDescription>
        </DialogHeader>

        <div className="flex flex-col gap-4 py-2">
          <div className="flex flex-col gap-1.5">
            <label
              htmlFor="walkin-name"
              className="text-sm font-medium leading-none"
            >
              お名前
            </label>
            <input
              id="walkin-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="例: 鈴木 様"
              className="inline-flex h-9 w-full rounded-lg border border-input bg-transparent px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-ring"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <NumberInput
              label="人数"
              layout="stepper"
              value={party}
              onValueChange={setParty}
              min={1}
              max={8}
            />
            <Select
              label="時間帯"
              value={slot}
              onChange={(e) => setSlot(e.target.value)}
            >
              {TIME_SLOTS.map((s) => (
                <option key={s} value={s}>
                  {s}
                </option>
              ))}
            </Select>
          </div>

          <Select
            label="卓（空席のみ）"
            description={
              fitting.length > 0
                ? `${party}名が入れる空卓: ${fitting.length}卓`
                : free.length > 0
                ? "人数に合う空卓がありません（席数不足の卓のみ空き）"
                : "この時間帯に空卓はありません"
            }
            value={tableId}
            onChange={(e) => setTableId(e.target.value)}
          >
            <option value="">選択してください</option>
            {free.map((id) => {
              const t = TABLES.find((x) => x.id === id)!;
              const tight = t.seats < party;
              return (
                <option key={id} value={id}>
                  卓{id}（{t.zone}・{t.seats}名{tight ? "・席数不足" : ""}）
                </option>
              );
            })}
          </Select>

          <Select
            label="担当"
            value={staff}
            onChange={(e) => setStaff(e.target.value)}
          >
            {STAFF_OPTIONS.filter((s) => s !== "—").map((s) => (
              <option key={s} value={s}>
                {s}
              </option>
            ))}
          </Select>
        </div>

        <DialogFooter>
          <Button variant="ghost" onClick={() => onOpenChange(false)}>
            キャンセル
          </Button>
          <Button variant="primary" disabled={!canSeat} onClick={handleSeat}>
            <IconUsers className="h-4 w-4" aria-hidden />
            着席させる
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

// 予約・来店管理画面 — 純粋ヘルパー & 表示メタ（関数 prop を含むので "use client" 側でのみ呼ぶ）
import type { BadgeProps } from "@gunjo/ui";
import {
  type Reservation,
  type ReservationStatus,
  type RequestTag,
  TABLES,
  TIME_SLOTS,
} from "./data";

// ── 来店状況の表示メタ ─────────────────────────────
export const STATUS_META: Record<
  ReservationStatus,
  { label: string; badge: NonNullable<BadgeProps["variant"]> }
> = {
  reserved: { label: "予約済", badge: "outline" },
  seated: { label: "来店中", badge: "info" },
  paid: { label: "会計済", badge: "success" },
  cancelled: { label: "キャンセル", badge: "secondary" },
  noshow: { label: "ノーショー", badge: "destructive" },
};

export const REQUEST_BADGE: Record<RequestTag["kind"], NonNullable<BadgeProps["variant"]>> = {
  allergy: "destructive",
  anniversary: "warning",
  seating: "info",
  other: "outline",
};

// 来店状況の遷移順（詳細パネルの操作ボタンに使う）
export const STATUS_ORDER: ReservationStatus[] = [
  "reserved",
  "seated",
  "paid",
];

// 卓 1 つが「いま埋まっている」とみなす状況
const OCCUPYING: ReservationStatus[] = ["seated"];
// 「今夜の枠を消費している」予約（キャンセル/ノーショーは除外）
const ACTIVE: ReservationStatus[] = ["reserved", "seated", "paid"];

export interface Summary {
  /** 予約組数（有効＝キャンセル/ノーショー除く） */
  parties: number;
  /** 総予約人数 */
  guests: number;
  /** 来店済（来店中＋会計済）組数 */
  arrived: number;
  /** いま着席中の卓数 */
  seatedTables: number;
  /** 満席率（着席中の卓 / 全卓） 0–100 */
  occupancyPct: number;
  /** 今夜 予約で埋まっている卓数（いずれかのスロットで有効予約） */
  reservedTables: number;
  /** ノーショー件数 */
  noshow: number;
  /** 予測売上（円） — 有効予約の人数 × 客単価合計 */
  forecastSales: number;
  /** 回転率（有効予約組数 / 全卓） */
  turnover: number;
}

export function summarize(reservations: Reservation[]): Summary {
  const active = reservations.filter((r) => ACTIVE.includes(r.status));
  const guests = active.reduce((s, r) => s + r.party, 0);
  const arrived = reservations.filter(
    (r) => r.status === "seated" || r.status === "paid"
  ).length;
  const seatedTables = new Set(
    reservations.filter((r) => OCCUPYING.includes(r.status)).map((r) => r.tableId)
  ).size;
  const reservedTables = new Set(active.map((r) => r.tableId)).size;
  const noshow = reservations.filter((r) => r.status === "noshow").length;
  const forecastSales = active.reduce((s, r) => s + r.party * r.spendPerHead, 0);

  return {
    parties: active.length,
    guests,
    arrived,
    seatedTables,
    occupancyPct: Math.round((seatedTables / TABLES.length) * 100),
    reservedTables,
    noshow,
    forecastSales,
    turnover: Math.round((active.length / TABLES.length) * 10) / 10,
  };
}

// ── 卓×時間グリッド：占有マップ ────────────────────
// あるスロットに、その卓を占める予約 id を列挙（重複検出のため配列）。
export type SlotMap = Map<string, string[]>; // key: `${tableId}::${slot}` → reservation ids

export function buildSlotMap(reservations: Reservation[]): SlotMap {
  const map: SlotMap = new Map();
  for (const r of reservations) {
    if (r.status === "cancelled" || r.status === "noshow") continue;
    const start = TIME_SLOTS.indexOf(r.time);
    if (start < 0) continue;
    for (let i = 0; i < r.durationSlots; i++) {
      const slot = TIME_SLOTS[start + i];
      if (!slot) break;
      const key = `${r.tableId}::${slot}`;
      const arr = map.get(key) ?? [];
      arr.push(r.id);
      map.set(key, arr);
    }
  }
  return map;
}

/** ダブルブッキングしている予約 id の集合（同一卓・同一スロットに2件以上） */
export function findDoubleBookings(slotMap: SlotMap): Set<string> {
  const conflicts = new Set<string>();
  for (const ids of slotMap.values()) {
    if (ids.length > 1) ids.forEach((id) => conflicts.add(id));
  }
  return conflicts;
}

/** 指定スロットで空いている卓（ウォークイン用） */
export function freeTablesAt(slot: string, slotMap: SlotMap): string[] {
  return TABLES.filter((t) => {
    const ids = slotMap.get(`${t.id}::${slot}`);
    return !ids || ids.length === 0;
  }).map((t) => t.id);
}

/** 円フォーマット（¥1,234,567）。Intl で十分なので軽量に。 */
export function yen(n: number): string {
  return "¥" + n.toLocaleString("ja-JP");
}
